fn factorial(n: i64) -> i64 =
    if n <= 1 { 1 } else { n * factorial(n - 1) };

fn main() -> i64
    pre n >= 0 and n <= 20
    post ret >= 1
= {
    let n = read_int();
    let i = 0;
    while i < n {
        let x = read_int();
        let _p = println(factorial(x));
        i = i + 1
    };
    0
};

